// IamServiceHandler is an implementation of the aes.iam.v1.IamService service.
type IamServiceHandler interface {
	// GetCallerIdentity returns the principal, default project, and project scope (if any) of
	// the calling key/token. Useful for clients (CLI / web) that want to display "logged in as"
	// without re-deriving from the bearer token.
	GetCallerIdentity(context.Context, *connect.Request[v1.GetCallerIdentityRequest]) (*connect.Response[v1.GetCallerIdentityResponse], error)
	// CreateApiKey mints a new API key for the calling principal. The secret is returned ONCE and
	// never persisted in plaintext — store it immediately. The key inherits the caller's principal
	// and a chosen default_project (the caller must have access to it).
	CreateApiKey(context.Context, *connect.Request[v1.CreateApiKeyRequest]) (*connect.Response[v1.CreateApiKeyResponse], error)
	// ListApiKeys lists keys owned by the calling principal. Returns metadata (display name, prefix,
	// create/expires/revoked timestamps) — never the secret.
	ListApiKeys(context.Context, *connect.Request[v1.ListApiKeysRequest]) (*connect.Response[v1.ListApiKeysResponse], error)
	// RevokeApiKey invalidates a key the caller owns. Idempotent on already-revoked keys.
	RevokeApiKey(context.Context, *connect.Request[v1.RevokeApiKeyRequest]) (*connect.Response[v1.RevokeApiKeyResponse], error)
	// SignUp self-provisions a new tenant: creates an organization, a default project, an IAM
	// binding marking the caller as admin of their org, and a fresh API key. Public (no auth) —
	// see docs/SIGNUP_PRODUCTION_HARDENING.md for the invite-gate / email-verification / OIDC
	// path that has to land before exposing this through a public gateway.
	SignUp(context.Context, *connect.Request[v1.SignUpRequest]) (*connect.Response[v1.SignUpResponse], error)
	// VerifyEmail consumes the token sent in the verification email + creates the user, org,
	// default project, and initial API key. Returns the API key the CLI / web stores for
	// subsequent calls.
	VerifyEmail(context.Context, *connect.Request[v1.VerifyEmailRequest]) (*connect.Response[v1.VerifyEmailResponse], error)
	// Login authenticates an email/password pair and returns a session API key. For OIDC users
	// (no password set), Login fails with FailedPrecondition; the caller should use the OIDC
	// flow instead. When the user's org has require_mfa=TRUE AND the user has an ACTIVE TOTP
	// device, the response contains only an mfa_challenge_token; the caller must finish via
	// SubmitMFAChallenge (P0-4).
	Login(context.Context, *connect.Request[v1.LoginRequest]) (*connect.Response[v1.LoginResponse], error)
	// SubmitMFAChallenge completes a two-leg login by validating a TOTP code (or single-use
	// recovery code) against the principal's enrolled MFA devices. Consumes the challenge token
	// returned by Login or CompleteOidcLogin and mints the session API key. 5-minute TTL,
	// single-use on success, max 5 wrong attempts before the challenge is invalidated and the
	// caller must restart from Login (P0-4).
	SubmitMFAChallenge(context.Context, *connect.Request[v1.SubmitMFAChallengeRequest]) (*connect.Response[v1.SubmitMFAChallengeResponse], error)
	// LinkOidcProvider attaches an OIDC identity (Google / GitHub / etc.) to the calling user.
	// After a successful link, that identity's CompleteOidcLogin will resolve to the same user.
	// Returns the same authorize_url + state shape as StartOidcLogin; the linking is finalized
	// when the caller's browser comes back through the standard CompleteOidcLogin path.
	LinkOidcProvider(context.Context, *connect.Request[v1.LinkOidcProviderRequest]) (*connect.Response[v1.LinkOidcProviderResponse], error)
	// Org membership management. InviteOrgMember issues a one-time accept token (caller is the
	// org admin); AcceptInvite is public (token-bearer) and creates the user + IAM binding when
	// redeemed. ListOrgMembers / RemoveOrgMember close the loop on the membership lifecycle.
	InviteOrgMember(context.Context, *connect.Request[v1.InviteOrgMemberRequest]) (*connect.Response[v1.InviteOrgMemberResponse], error)
	AcceptInvite(context.Context, *connect.Request[v1.AcceptInviteRequest]) (*connect.Response[v1.AcceptInviteResponse], error)
	// SetInitialPassword sets a password on an account that has none (typical: invite-accepted
	// user who hasn't linked GitHub yet). Only allowed when password_hash is empty AND the
	// caller has no OIDC identities — established accounts use ChangePassword instead. Caller
	// must be authenticated (the AcceptInvite session token works).
	SetInitialPassword(context.Context, *connect.Request[v1.SetInitialPasswordRequest]) (*connect.Response[v1.SetInitialPasswordResponse], error)
	ListOrgMembers(context.Context, *connect.Request[v1.ListOrgMembersRequest]) (*connect.Response[v1.ListOrgMembersResponse], error)
	RemoveOrgMember(context.Context, *connect.Request[v1.RemoveOrgMemberRequest]) (*connect.Response[v1.RemoveOrgMemberResponse], error)
	// UpdateOrgMemberRole swaps a member's role binding without forcing a remove+re-invite.
	// Caller must hold admin.organization. Same role validation as InviteOrgMember.
	UpdateOrgMemberRole(context.Context, *connect.Request[v1.UpdateOrgMemberRoleRequest]) (*connect.Response[v1.UpdateOrgMemberRoleResponse], error)
	// ListPendingInvites surfaces unaccepted invites for an org so admins can resend or revoke.
	// Filters to PENDING + not-yet-expired. Caller must hold admin.organization.
	ListPendingInvites(context.Context, *connect.Request[v1.ListPendingInvitesRequest]) (*connect.Response[v1.ListPendingInvitesResponse], error)
	// RevokeInvite marks a pending invite REVOKED so the token can't be accepted later.
	// Idempotent on already-revoked rows. Caller must hold admin.organization.
	RevokeInvite(context.Context, *connect.Request[v1.RevokeInviteRequest]) (*connect.Response[v1.RevokeInviteResponse], error)
	// ── Self-service multi-org (the org switcher + in-app invites) ────────────────────────────
	// ListMyOrganizations returns every org the caller is a member of, with the caller's role +
	// the org's state. Backs the org switcher (and the account page's memberships list).
	ListMyOrganizations(context.Context, *connect.Request[v1.ListMyOrganizationsRequest]) (*connect.Response[v1.ListMyOrganizationsResponse], error)
	// ListMyInvites returns PENDING, unexpired org invites addressed to the caller's email — the
	// in-app invitations inbox (no email round-trip needed to find/accept them).
	ListMyInvites(context.Context, *connect.Request[v1.ListMyInvitesRequest]) (*connect.Response[v1.ListMyInvitesResponse], error)
	// AcceptMyInvite accepts a pending invite by id while authenticated. The invite's email must
	// resolve to the caller's principal; on success it adds the org role binding. No token needed
	// (the session is the proof) — distinct from the public token-bearer AcceptInvite.
	AcceptMyInvite(context.Context, *connect.Request[v1.AcceptMyInviteRequest]) (*connect.Response[v1.AcceptMyInviteResponse], error)
	// DeclineMyInvite marks one of the caller's pending invites DECLINED.
	DeclineMyInvite(context.Context, *connect.Request[v1.DeclineMyInviteRequest]) (*connect.Response[v1.DeclineMyInviteResponse], error)
	// RotateApiKey atomically issues a new key + revokes the old one in a single call. Use
	// instead of revoke-then-create to avoid the window where neither key is valid.
	RotateApiKey(context.Context, *connect.Request[v1.RotateApiKeyRequest]) (*connect.Response[v1.RotateApiKeyResponse], error)
	// OIDC customer login flow. StartOidcLogin returns the IdP authorize URL the customer's
	// browser redirects to (with state + nonce). After the IdP redirects back to Metalhost's
	// /oauth/callback, the gateway calls CompleteOidcLogin with the authorization code; we
	// exchange it with the IdP, validate the ID token, find-or-create the user, and mint an
	// API key for the session.
	StartOidcLogin(context.Context, *connect.Request[v1.StartOidcLoginRequest]) (*connect.Response[v1.StartOidcLoginResponse], error)
	CompleteOidcLogin(context.Context, *connect.Request[v1.CompleteOidcLoginRequest]) (*connect.Response[v1.CompleteOidcLoginResponse], error)
	// CreateWorkspace is the self-serve org bootstrap the onboarding wizard calls for an
	// authenticated-but-org-less user (the state an SSO/OIDC first-login lands in — the identity
	// is created at login, but the user names their workspace here). It creates the org chain
	// (organization + quota defaults + billing account + USD wallet + organization.admin binding
	// for the caller) under the caller's chosen slug, in one transaction. Idempotent-safe: a slug
	// already taken by a different account is refused (the takeover gate). The chosen slug is
	// validated against the same DNS-1035 + reserved rules CheckSlugAvailable reports on.
	CreateWorkspace(context.Context, *connect.Request[v1.CreateWorkspaceRequest]) (*connect.Response[v1.CreateWorkspaceResponse], error)
	// MFA / TOTP. EnrollMFA returns a fresh shared secret + provisioning URI (otpauth://) the
	// caller's authenticator app reads as a QR code; the credential starts in PENDING state and
	// does nothing until VerifyMFAEnrollment confirms a valid TOTP code. ListMFADevices reports
	// the principal's enrolled devices; RevokeMFADevice deactivates one. Recovery codes are
	// issued on first verification (one-shot, hashed at rest) so a lost authenticator doesn't
	// lock the user out — they're returned in VerifyMFAEnrollmentResponse.recovery_codes.
	EnrollMFA(context.Context, *connect.Request[v1.EnrollMFARequest]) (*connect.Response[v1.EnrollMFAResponse], error)
	VerifyMFAEnrollment(context.Context, *connect.Request[v1.VerifyMFAEnrollmentRequest]) (*connect.Response[v1.VerifyMFAEnrollmentResponse], error)
	ListMFADevices(context.Context, *connect.Request[v1.ListMFADevicesRequest]) (*connect.Response[v1.ListMFADevicesResponse], error)
	RevokeMFADevice(context.Context, *connect.Request[v1.RevokeMFADeviceRequest]) (*connect.Response[v1.RevokeMFADeviceResponse], error)
	// RegenerateRecoveryCodes replaces the caller's recovery-code set with a fresh one.
	// Requires a current TOTP code. Returned ONCE — store immediately.
	RegenerateRecoveryCodes(context.Context, *connect.Request[v1.RegenerateRecoveryCodesRequest]) (*connect.Response[v1.RegenerateRecoveryCodesResponse], error)
	// Session management. Sessions are the metadata around interactive logins (OIDC, signup,
	// invite-accept) — each one is linked to an API key. ListSessions shows the caller their
	// active sessions; RevokeSession invalidates one (revokes the linked API key); RevokeAll
	// revokes every session except the one calling (so users can "log out everywhere else"
	// without locking themselves out). Programmatic API keys created via CreateApiKey are NOT
	// sessions and don't appear here — they're managed via ListApiKeys / RevokeApiKey.
	ListSessions(context.Context, *connect.Request[v1.ListSessionsRequest]) (*connect.Response[v1.ListSessionsResponse], error)
	RevokeSession(context.Context, *connect.Request[v1.RevokeSessionRequest]) (*connect.Response[v1.RevokeSessionResponse], error)
	RevokeAllOtherSessions(context.Context, *connect.Request[v1.RevokeAllOtherSessionsRequest]) (*connect.Response[v1.RevokeAllOtherSessionsResponse], error)
	// Logout revokes the calling session + its API key in one shot. Distinct from RevokeSession
	// (which takes a session id) because the SPA's session cookie is HttpOnly — JS can't read
	// the session id to pass into RevokeSession. The gateway clears the mh_session +
	// mh_signed_in cookies on a successful response.
	Logout(context.Context, *connect.Request[v1.LogoutRequest]) (*connect.Response[v1.LogoutResponse], error)
	// Password reset. RequestPasswordReset is anonymous — emits a token to the email IF it
	// matches an active user, but always returns ok=true (no enumeration). ResetPassword
	// consumes the token + sets a new bcrypt'd password + invalidates all the user's sessions
	// (someone who triggered a reset should re-login from scratch on the trusted device).
	RequestPasswordReset(context.Context, *connect.Request[v1.RequestPasswordResetRequest]) (*connect.Response[v1.RequestPasswordResetResponse], error)
	ResetPassword(context.Context, *connect.Request[v1.ResetPasswordRequest]) (*connect.Response[v1.ResetPasswordResponse], error)
	// Profile management. GetUser returns the user's display info (callable for any user the
	// caller can read; passing an empty name returns the caller's own profile). UpdateUser
	// changes mutable profile fields. ChangePassword rotates the bcrypt hash after verifying
	// the current one. RequestEmailChange swaps users.email immediately and fires a heads-up
	// to the previous address (the session itself is the auth — no second-leg confirmation).
	GetUser(context.Context, *connect.Request[v1.GetUserRequest]) (*connect.Response[v1.GetUserResponse], error)
	UpdateUser(context.Context, *connect.Request[v1.UpdateUserRequest]) (*connect.Response[v1.UpdateUserResponse], error)
	ChangePassword(context.Context, *connect.Request[v1.ChangePasswordRequest]) (*connect.Response[v1.ChangePasswordResponse], error)
	RequestEmailChange(context.Context, *connect.Request[v1.RequestEmailChangeRequest]) (*connect.Response[v1.RequestEmailChangeResponse], error)
	// ImportGitHubSshKeys fetches the user's public SSH keys from GitHub's public endpoint
	// (https://github.com/<username>.keys, no auth required) and bulk-creates SSHKey rows under
	// the target project. Onboarding shortcut: the wizard offers "Import from GitHub" so users
	// who signed up via the GitHub OAuth flow don't have to paste keys manually. Existing keys
	// with the same fingerprint are skipped; only new keys are created. Returns the list of
	// keys actually created (display_name, fingerprint) for UI feedback.
	ImportGitHubSshKeys(context.Context, *connect.Request[v1.ImportGitHubSshKeysRequest]) (*connect.Response[v1.ImportGitHubSshKeysResponse], error)
	// ListNotifications returns customer-notable events for the bell-icon feed (top-up
	// succeeded, VM op completed, spending alert triggered, etc.). Backed by audit_events
	// filtered through the same notify_in_app classifier used by ListOrgActivity, joined to
	// notification_reads so the caller knows what they've already seen. The 30-day window is
	// enforced server-side. Use ListOrgActivity for the full audit log; this is the curated
	// notification subset.
	ListNotifications(context.Context, *connect.Request[v1.ListNotificationsRequest]) (*connect.Response[v1.ListNotificationsResponse], error)
	// MarkNotificationsRead upserts notification_reads rows so the bell badge count clears.
	// Pass `mark_all=true` to mark every visible notification read; otherwise pass explicit
	// event ids. Idempotent — re-marking an already-read row is a no-op.
	MarkNotificationsRead(context.Context, *connect.Request[v1.MarkNotificationsReadRequest]) (*connect.Response[v1.MarkNotificationsReadResponse], error)
}

